 * mmap anonyme pour un buffer d'entiers
 * Pattern: mmap(MAP_ANONYMOUS) + cast + munmap
 * ================================================= */
void example_mmap(void) {
    size_t sz = (size_t)sysconf(_SC_PAGESIZE);
    int *arr = mmap(NULL, sz, PROT_READ | PROT_WRITE,
                    MAP_PRIVATE | MAP_ANONYMOUS, -1, 0);
    if (arr == MAP_FAILED) return;
    for (int i = 0; i < 5; i++) arr[i] = i * 10;
    for (int i = 0; i < 5; i++) printf("%d ", arr[i]);
    printf("\n");
    munmap(arr, sz);
}
